#include <bits/stdc++.h>
using namespace std;
int n,l=1;
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			if(l<10){
				cout<<"0";
			}
			cout<<l++;
		}
		cout<<"\n";
	}
	cout<<"\n";
	l=1;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			if(j>n-i){
				if(l<10){
					cout<<0;
				}
				cout<<l++;
			}else{
				cout<<"  ";
			}
		}
		cout<<"\n";
	}
	return 0;
}
